package be.schaubroeck.lpb.rkm.rekenmotor.rsz.werkbonus;

import be.schaubroeck.lpb.rkm.rekenmotor.RekenContext;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.bruto.FlexiJobsUtil;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RegulManager;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.enumtypes.DmfapplNotieGepens;
import be.schaubroeck.lpb.tools.enumtypes.RekenControleCode;
import lombok.AllArgsConstructor;

@AllArgsConstructor
public class WerkbonusGepensioneerdUitbreidingOpdrachtNodig {

    private static final String OPMERKING = "Pers komt evt in aanmerk. voor de vrijst. van bijdr vr gepens tew. in de zorg. " +
            "Was betrok. gepens op 1/7/22. Zo ja vervroeg de opdr tot 1/7, plaats de per. met dienstverb. neen en herreken de act. per.";

    private final WerkbonusGepensioneerdOpdracht checkOpdracht;
    private final WerkbonusGepensioneerdOpper checkOpper;

    public void check(RekenContext opdrachtContext, Opdracht opdracht, RegulManager regulManager) {
        RekenTijd rekenTijd = opdrachtContext.getUnchecked(RekenChainKey.REKENTIJD_KEY);
        if (isOpdrachtGestartNaStart(opdracht) && isNotieGepensioneerd(opdrachtContext) && niet65VoorEersteDagMaand(opdrachtContext, opdracht) &&
                erIsEenOpperAanmerking(opdracht, rekenTijd) && geenFlexiJob(opdracht)) {
            regulManager.addProtoWaarschuwing(opdracht, RekenControleCode.CONTROLE_WERKBONUS_GEPENSIONEERD, OPMERKING);
        }
    }

    private boolean isNotieGepensioneerd(RekenContext opdrachtContext) {
        Opper opper = opdrachtContext.getUnchecked(RekenChainKey.OPPER_LAATSTE_GEGEVENS_KEY);
        return opper.getRszppo().getNotieGepensioneerd() == DmfapplNotieGepens.GEPENSION;
    }

    private boolean isOpdrachtGestartNaStart(Opdracht opdracht) {
        return WerkbonusGepensioneerdActief.getStartDatum().isBefore(opdracht.getBeginDatum());
    }

    private boolean niet65VoorEersteDagMaand(RekenContext opdrachtContext, Opdracht opdracht) {
        return !checkOpdracht.is65VoorEersteDagMaand(opdrachtContext, opdracht);
    }

    private boolean erIsEenOpperAanmerking(Opdracht opdracht, RekenTijd rekenTijd) {
        return opdracht.getOpperSlices().stream().anyMatch(opper -> checkOpper.komtInAanMerking(opper, rekenTijd));
    }

    private boolean geenFlexiJob(Opdracht opdracht) {
        return !opdracht.getOpperSlices().stream().map(Opper::getRszppo).allMatch(FlexiJobsUtil::isWnKengetalFlexiJob);
    }


}
